import { type SetStateAction, useState } from 'react';
import { replaceEqualDeep } from '../lib/replace-equal-deep';
import { useStableCallback } from './use-stable-callback';

/**
 * A version of `useState` that uses deep equality to compare the previous and new state, and only updates the state if the new state is different.
 * This is useful when the state is a complex object and we want to avoid unnecessary re-renders.
 */
export function useStructuralState<S>(initialState: S | (() => S)) {
  const [state, setStateRaw] = useState(initialState);

  const setState = useStableCallback((newState: SetStateAction<S>) => {
    setStateRaw(prevState => {
      const newStateValue = typeof newState === 'function' ? (newState as (prevState: S) => S)(prevState) : newState;
      return replaceEqualDeep(prevState, newStateValue);
    });
  });

  return [state, setState] as const;
}
